1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = { type: string; cursed?: boolean; enchantment?: number };
13	type Step = { op?: string; items: Item[] };
14	type Customer = { yearsWithMHPCO: number };
15	type Scenario = { customer: Customer; steps: Step[] };
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	const BLOCK_BASE_PREMIUM = 60;
19	
20	function computeQuotePremium(
21	  items: Item[],
22	  customer: Customer,
23	  quoteIndex: number,
24	): number {
25	  const componentCountsByType = new Map<string, number>();
26	  let itemAdjustedSum = 0;
27	  let policyBasePremium = 0;
28	  for (const item of items) {
29	    if (COMPONENT_TYPES.has(item.type)) {
30	      componentCountsByType.set(
31	        item.type,
32	        (componentCountsByType.get(item.type) ?? 0) + 1,
33	      );
34	    } else {
35	      const base = BASE_PREMIUM_BY_ITEM_TYPE[item.type] ?? 0;
36	      let itemPremium = base;
37	      if (item.cursed) {
38	        itemPremium += base * 0.5;
39	      }
40	      if (item.enchantment !== undefined && item.enchantment >= 5) {
41	        itemPremium += base * 0.3;
42	      }
43	      itemPremium += base * 0.1;
44	      itemAdjustedSum += itemPremium;
45	      policyBasePremium += base;
46	    }
47	  }
48	  for (const [type, count] of componentCountsByType) {
49	    if (count === 3) {
50	      itemAdjustedSum += BLOCK_BASE_PREMIUM + BLOCK_BASE_PREMIUM * 0.1;
51	      policyBasePremium += BLOCK_BASE_PREMIUM;
52	    } else {
53	      const componentBase = BASE_PREMIUM_BY_ITEM_TYPE[type] ?? 0;
54	      itemAdjustedSum += count * (componentBase + componentBase * 0.1);
55	      policyBasePremium += count * componentBase;
56	    }
57	  }
58	  let loyaltyDiscount = 0;
59	  if (customer.yearsWithMHPCO >= 2) {
60	    loyaltyDiscount = policyBasePremium * 0.2;
61	  }
62	  let followUpDiscount = 0;
63	  if (quoteIndex >= 1) {
64	    followUpDiscount = policyBasePremium * 0.15;
65	  }
66	  return Math.ceil(
67	    itemAdjustedSum - loyaltyDiscount - followUpDiscount + PROCESSING_FEE,
68	  );
69	}
70	
71	export function processScenario(scenario: unknown): unknown {
72	  const { customer, steps } = scenario as Scenario;
73	  const results: { premium: number }[] = [];
74	  let quoteIndex = 0;
75	  for (const step of steps) {
76	    const premium = computeQuotePremium(step.items, customer, quoteIndex);
77	    results.push({ premium });
78	    quoteIndex += 1;
79	  }
80	  return { results };
81	}
